import UIKit
import SwiftUI

// MARK: - Password Reset Routing

public enum AppRoute: Equatable {
    case resetPassword(token: String)
}

public enum UniversalLinkRouter {
    public static let allowedHosts: Set<String> = ["myapp.com", "www.myapp.com"]

    public static func route(from url: URL) -> AppRoute? {
        guard url.scheme?.lowercased() == "https" else { return nil }
        guard let host = url.host?.lowercased(), allowedHosts.contains(host) else { return nil }

        let path = url.path.lowercased()
        guard path == "/reset-password" else { return nil }

        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }
        let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value

        guard let token, !token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return nil }
        return .resetPassword(token: token)
    }
}

// MARK: - Coordinator

@MainActor
public final class AppCoordinator: ObservableObject {
    public static let shared = AppCoordinator()

    @Published public private(set) var route: AppRoute?

    private init() {}

    public func handle(url: URL) {
        if let route = UniversalLinkRouter.route(from: url) {
            self.route = route
        }
    }

    public func clearRoute() {
        self.route = nil
    }
}

// MARK: - UIKit Integration (AppDelegate / SceneDelegate)

final class AppDelegate: UIResponder, UIApplicationDelegate {
    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL
        else { return false }

        Task { @MainActor in
            AppCoordinator.shared.handle(url: url)
        }
        return true
    }
}

final class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    var window: UIWindow?

    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL
        else { return }

        Task { @MainActor in
            AppCoordinator.shared.handle(url: url)
        }
    }
}

// MARK: - SwiftUI App Integration

@main
struct MyApp: App {
    @UIApplicationDelegateAdaptor(AppDelegate.self) var appDelegate
    @StateObject private var coordinator = AppCoordinator.shared

    var body: some Scene {
        WindowGroup {
            RootView()
                .environmentObject(coordinator)
                .onOpenURL { url in
                    coordinator.handle(url: url)
                }
        }
    }
}

// MARK: - Root + Navigation to Reset Screen

struct RootView: View {
    @EnvironmentObject private var coordinator: AppCoordinator

    var body: some View {
        NavigationStack {
            HomeView()
                .navigationDestination(item: Binding(
                    get: { RouteWrapper(coordinator.route) },
                    set: { _ in }
                )) { wrapper in
                    switch wrapper.route {
                    case .resetPassword(let token):
                        PasswordResetView(token: token) {
                            coordinator.clearRoute()
                        }
                    }
                }
                .onChange(of: coordinator.route) { _, _ in }
        }
    }
}

private struct RouteWrapper: Identifiable, Equatable {
    let id: String
    let route: AppRoute

    init?(_ route: AppRoute?) {
        guard let route else { return nil }
        self.route = route
        switch route {
        case .resetPassword(let token):
            self.id = "resetPassword:\(token)"
        }
    }
}

